#include<iostream>#include<vector>#include<algorithm>#include<climits>#define ll long longusing namespace std; int main(){    ios_base::sync_with_stdio(false);    cin.tie(NULL);    int t;    cin>>t;    while(t--){        ll n,k;        cin>>n>>k;        vector<ll> a(n);        for(int i=0;i<n;i++){            cin>>a[i];        }        vector<ll>b(n);        for(int i=0;i<n;i++){            cin>>b[i];        }        ll sum=0;        ll max_sum= LLONG_MIN;        if(k==1){            max_sum= a[0];        }        else{            ll curr_max_b= LLONG_MIN;        for(int i=0;i<n;i++){            sum+= a[i];            int left_numbers= k-(i+1);            if(left_numbers<=0){                max_sum= max(max_sum,sum);                break;            }                        curr_max_b= max(curr_max_b, b[i]);            ll curr_exp= sum + curr_max_b*left_numbers;            max_sum= max(max_sum,curr_exp);        }        }            cout<<max_sum<<"\n";     }}